import{_ as e,o as a,c as i,ag as o}from"./chunks/framework.Dn0B0GT3.js";const p=JSON.parse(`{"title":"Security","description":"Understanding ShellPort's four security modes and when to use each","frontmatter":{"title":"Security","description":"Understanding ShellPort's four security modes and when to use each"},"headers":[],"relativePath":"guides/security.md","filePath":"guides/security.md"}`),r={name:"guides/security.md"};function s(n,t,l,d,h,c){return a(),i("div",null,[...t[0]||(t[0]=[o('<h1 id="security" tabindex="-1">Security <a class="header-anchor" href="#security" aria-label="Permalink to &quot;Security&quot;">​</a></h1><p>ShellPort provides four security modes that balance encryption, authentication, and ease of use. Choose the mode that fits your network environment and trust model.</p><h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Mode</th><th>Command</th><th>Auth</th><th>Encryption</th><th>Use Case</th></tr></thead><tbody><tr><td><strong>Full security</strong></td><td><code>shellport server</code></td><td>Secret + TOTP</td><td>AES-256-GCM</td><td>Default — maximum security</td></tr><tr><td><strong>Encrypted only</strong></td><td><code>shellport server --no-totp</code></td><td>URL secret</td><td>AES-256-GCM</td><td>Trusted environment</td></tr><tr><td><strong>TOTP only</strong></td><td><code>shellport server --no-secret</code></td><td>TOTP code</td><td>None*</td><td>Remote via VPN/Tailscale</td></tr><tr><td><strong>Plaintext</strong></td><td><code>shellport server --no-secret --no-totp</code></td><td>None</td><td>None</td><td>Localhost dev only</td></tr></tbody></table><p>* When using TOTP-only mode over Tailscale/WireGuard, the VPN tunnel provides encryption at the network layer.</p><hr><h2 id="full-security-default" tabindex="-1">Full Security (Default) <a class="header-anchor" href="#full-security-default" aria-label="Permalink to &quot;Full Security (Default)&quot;">​</a></h2><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">shellport</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> server</span></span></code></pre></div><h3 id="what-it-does" tabindex="-1">What it does <a class="header-anchor" href="#what-it-does" aria-label="Permalink to &quot;What it does&quot;">​</a></h3><ul><li><strong>Encryption:</strong> AES-256-GCM with per-session key derivation</li><li><strong>Authentication:</strong> 128-bit auto-generated secret + TOTP 2FA</li><li><strong>Approval:</strong> Interactive prompt to approve each connection</li></ul><h3 id="when-to-use" tabindex="-1">When to use <a class="header-anchor" href="#when-to-use" aria-label="Permalink to &quot;When to use&quot;">​</a></h3><p>This is the <strong>recommended mode for production use</strong>. Use it when:</p><ul><li>The server is accessible from the internet</li><li>You need the highest level of security</li><li>Multiple users will be connecting</li><li>You&#39;re unsure which mode to choose</li></ul><h3 id="how-it-works" tabindex="-1">How it works <a class="header-anchor" href="#how-it-works" aria-label="Permalink to &quot;How it works&quot;">​</a></h3><ol><li>Server generates a random 128-bit secret</li><li>Share the secret via the URL fragment (<code>#secret</code>)</li><li>User scans the QR code to pair their authenticator app</li><li>On each connection, both secret and TOTP code are verified</li></ol><hr><h2 id="encrypted-only" tabindex="-1">Encrypted Only <a class="header-anchor" href="#encrypted-only" aria-label="Permalink to &quot;Encrypted Only&quot;">​</a></h2><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">shellport</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> server</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --no-totp</span></span></code></pre></div><h3 id="what-it-does-1" tabindex="-1">What it does <a class="header-anchor" href="#what-it-does-1" aria-label="Permalink to &quot;What it does&quot;">​</a></h3><ul><li><strong>Encryption:</strong> AES-256-GCM with auto-generated secret</li><li><strong>Authentication:</strong> URL secret only</li><li><strong>Approval:</strong> Interactive prompt (if not disabled)</li></ul><h3 id="when-to-use-1" tabindex="-1">When to use <a class="header-anchor" href="#when-to-use-1" aria-label="Permalink to &quot;When to use&quot;">​</a></h3><p>Use this mode when:</p><ul><li>You&#39;re on a trusted network (e.g., home LAN, corporate VPN)</li><li>TOTP is too cumbersome for frequent reconnections</li><li>You want encryption without the overhead of 2FA</li></ul><h3 id="security-considerations" tabindex="-1">Security considerations <a class="header-anchor" href="#security-considerations" aria-label="Permalink to &quot;Security considerations&quot;">​</a></h3><p>The secret is 128 bits and auto-generated per session, making brute-force attacks computationally infeasible. However, without TOTP, anyone who obtains the URL (including the secret in the fragment) can connect.</p><hr><h2 id="totp-only" tabindex="-1">TOTP Only <a class="header-anchor" href="#totp-only" aria-label="Permalink to &quot;TOTP Only&quot;">​</a></h2><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">shellport</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> server</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --no-secret</span></span></code></pre></div><h3 id="what-it-does-2" tabindex="-1">What it does <a class="header-anchor" href="#what-it-does-2" aria-label="Permalink to &quot;What it does&quot;">​</a></h3><ul><li><strong>Encryption:</strong> None (plaintext)</li><li><strong>Authentication:</strong> TOTP 2FA code only</li><li><strong>Approval:</strong> Interactive prompt (if not disabled)</li></ul><h3 id="when-to-use-2" tabindex="-1">When to use <a class="header-anchor" href="#when-to-use-2" aria-label="Permalink to &quot;When to use&quot;">​</a></h3><p>Use this mode when:</p><ul><li>You&#39;re connected via a VPN that provides network-level encryption (Tailscale, WireGuard)</li><li>You want simple access with 2FA protection</li><li>The VPN ensures no one can eavesdrop on the connection</li></ul><h3 id="security-considerations-1" tabindex="-1">Security considerations <a class="header-anchor" href="#security-considerations-1" aria-label="Permalink to &quot;Security considerations&quot;">​</a></h3><p>Without a VPN, all terminal traffic is visible in plaintext. Only use this mode when running over an encrypted tunnel like Tailscale. The TOTP secret is stored in <code>~/.shellport-totp-secret</code>.</p><hr><h2 id="plaintext" tabindex="-1">Plaintext <a class="header-anchor" href="#plaintext" aria-label="Permalink to &quot;Plaintext&quot;">​</a></h2><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">shellport</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> server</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --no-secret</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --no-totp</span></span></code></pre></div><h3 id="what-it-does-3" tabindex="-1">What it does <a class="header-anchor" href="#what-it-does-3" aria-label="Permalink to &quot;What it does&quot;">​</a></h3><ul><li><strong>Encryption:</strong> None</li><li><strong>Authentication:</strong> None</li><li><strong>Approval:</strong> Interactive prompt (if not disabled)</li></ul><h3 id="when-to-use-3" tabindex="-1">When to use <a class="header-anchor" href="#when-to-use-3" aria-label="Permalink to &quot;When to use&quot;">​</a></h3><p>Use this mode <strong>only</strong> when:</p><ul><li>Running on <code>localhost</code> for local development</li><li>The server is on an isolated network with no external access</li><li>You need the simplest possible setup for testing</li></ul><div class="danger custom-block"><p class="custom-block-title">DANGER</p><p>This mode provides no security. All terminal data is transmitted in plaintext and there is no authentication. Never use this on any server accessible from the internet or on untrusted networks.</p></div><hr><h2 id="security-layers" tabindex="-1">Security Layers <a class="header-anchor" href="#security-layers" aria-label="Permalink to &quot;Security Layers&quot;">​</a></h2><h3 id="encryption" tabindex="-1">Encryption <a class="header-anchor" href="#encryption" aria-label="Permalink to &quot;Encryption&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Parameter</th><th>Value</th></tr></thead><tbody><tr><td>Algorithm</td><td>AES-256-GCM</td></tr><tr><td>Key Derivation</td><td>PBKDF2 · 100,000 iterations · SHA-256</td></tr><tr><td>IV</td><td>12-byte random nonce per message</td></tr><tr><td>Secret Size</td><td>128 bits (16 bytes)</td></tr></tbody></table><h3 id="authentication" tabindex="-1">Authentication <a class="header-anchor" href="#authentication" aria-label="Permalink to &quot;Authentication&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Method</th><th>Description</th></tr></thead><tbody><tr><td>URL Fragment</td><td>Secret passed via <code>#secret</code> — never sent to server</td></tr><tr><td>TOTP</td><td>RFC 6238 — SHA-1, 6 digits, 30-second window</td></tr><tr><td>Proof-of-Key</td><td>Client must decrypt a server nonce to prove key possession</td></tr></tbody></table><h3 id="connection-security" tabindex="-1">Connection Security <a class="header-anchor" href="#connection-security" aria-label="Permalink to &quot;Connection Security&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Feature</th><th>Description</th></tr></thead><tbody><tr><td>Rate Limiting</td><td>5 connection attempts per IP per minute</td></tr><tr><td>Session Cap</td><td>Maximum 10 concurrent PTY sessions</td></tr><tr><td>Origin Validation</td><td>WebSocket accepts same-origin only (localhost bypass requires <code>--dev</code>)</td></tr></tbody></table><hr><h2 id="best-practices" tabindex="-1">Best Practices <a class="header-anchor" href="#best-practices" aria-label="Permalink to &quot;Best Practices&quot;">​</a></h2><ol><li><strong>Keep TOTP enabled</strong> — It&#39;s on by default for a reason</li><li><strong>Use approval mode</strong> — The interactive approval prompt adds an extra layer of security</li><li><strong>Never use plaintext mode</strong> on exposed servers</li><li><strong>Use <code>--no-secret</code> only with VPN</strong> — Tailscale provides network-layer encryption</li><li><strong>Protect <code>~/.shellport-totp-secret</code></strong> — This file contains your TOTP pairing secret</li></ol><p>For more details on the cryptographic implementation, see the <a href="/shellport/shellport/internals/security.html">Security Model</a> page.</p>',56)])])}const y=e(r,[["render",s]]);export{p as __pageData,y as default};
